  }).join("; ");

  const customContext = config.customApproach ? `Custom Methodology: ${config.customApproach}` : "";

  // -- STEP 1: LIBRARIAN AGENT EXECUTION --
  let researchDossier: LibrarianDossier = { bibliography: [], researchSummary: "", rawSources: [] };

  if (config.autoResearch) {
    log("Activating Librarian Agent", "正在啟動圖書管理員代理", 'processing');
    researchDossier = await generateResearchDossier(config, log);
