          <button
            onClick={handleAutoGenerateTopic}
            disabled={!config.passage || isGeneratingTopic}
            className={`flex items-center gap-1.5 text-xs font-bold transition-colors uppercase tracking-wider
              ${!config.passage || isGeneratingTopic ? 'text-stone-300 cursor-not-allowed' : 'text-stone-400 hover:text-accent'}`}
          >
            <span className={`material-symbols-outlined text-sm ${isGeneratingTopic ? 'animate-spin' : ''}`}>
              {isGeneratingTopic ? 'autorenew' : 'bolt'}
            </span>
            {t.generateIdeas[langKey]}
          </button>
        </div>
        <input
          type="text"
          value={config.topic}
          onChange={(e) => onChange({ topic: e.target.value })}
          placeholder={t.topicPlaceholder[langKey]}
          className="w-full bg-white border-2 border-transparent focus:border-accent/50 ring-1 ring-stone-200 rounded-2xl px-6 py-5 text-lg font-serif text-[#2c2c2c] placeholder:text-stone-300 focus:outline-none focus:ring-4 focus:ring-accent/10 shadow-soft transition-all"
        />

        {/* Topic Suggestions Grid */}
        {topicSuggestions.length > 0 && (
          <div className="grid gap-3 pt-4 animate-fade-in">
            <p className="text-[10px] font-bold text-primary uppercase tracking-[0.2em]">
              {t.selectTheme[langKey]}
            </p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {topicSuggestions.map((suggestion, idx) => (
                <button
                  key={idx}
                  onClick={() => handleSelectTopic(suggestion)}
                  className="text-left p-4 rounded-xl border border-stone-200 bg-white hover:border-primary/40 hover:shadow-md transition-all group"
                >
                  <span className="font-serif text-base font-bold text-text-main group-hover:text-primary block leading-tight">
                    {suggestion}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Selectors Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="flex flex-col gap-3">
          <label className="text-base font-bold text-[#4a4a4a] uppercase tracking-wider">
            {t.knowledgeLabel[langKey]}
          </label>
          <div className="relative">
            <select
              value={config.knowledgeLevel}
              onChange={(e) => onChange({ knowledgeLevel: e.target.value as KnowledgeLevel })}
              className="w-full appearance-none bg-white ring-1 ring-stone-200 rounded-xl px-5 py-4 text-base font-medium text-[#2c2c2c] focus:outline-none focus:ring-2 focus:ring-accent shadow-sm cursor-pointer border-none"
            >
              {Object.values(KnowledgeLevel).map((level) => (
                <option key={level} value={level}>
                  {KNOWLEDGE_LEVEL_LABELS[level][langKey]}
                </option>
              ))}
            </select>
            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-stone-500">
              <span className="material-symbols-outlined">expand_more</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-3">
          <label className="text-base font-bold text-[#4a4a4a] uppercase tracking-wider">
            {t.typeLabel[langKey]}
          </label>
          <div className="relative">
            <select
              value={config.studyType}
              onChange={(e) => onChange({ studyType: e.target.value as StudyType })}
              className="w-full appearance-none bg-white ring-1 ring-stone-200 rounded-xl px-5 py-4 text-base font-medium text-[#2c2c2c] focus:outline-none focus:ring-2 focus:ring-accent shadow-sm cursor-pointer border-none"
            >
              {Object.values(StudyType).map((type) => (
                <option key={type} value={type}>
                  {STUDY_TYPE_LABELS[type][langKey]}
                </option>
              ))}
            </select>
            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-stone-500">
              <span className="material-symbols-outlined">expand_more</span>
            </div>
          </div>
        </div>
      </div>

      {/* Target Duration Slider per stitch code */}
      <div className="flex flex-col gap-4 mt-2">
        <div className="flex justify-between items-center">
          <label className="text-base font-bold text-[#4a4a4a] uppercase tracking-wider">{t.durationLabel[langKey]}</label>
          <span className="text-lg font-bold text-[#3f6212]">{config.duration} {t.minutes[langKey]}</span>
        </div>
        <div className="relative w-full h-12 flex items-center">
          <input
            type="range"
            min="15"
            max="180"
            step="15"
            value={config.duration}
            onChange={(e) => onChange({ duration: parseInt(e.target.value) })}
            className="w-full h-2 bg-[#e5e5e0] rounded-lg appearance-none cursor-pointer accent-[#3f6212]"
          />
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import Markdown from 'react-markdown';
import { Language, ActivityLog } from '../types';
import { UI_TEXT } from '../constants';
import { ChatSession } from './ChatSession';

interface ResultDisplayProps {
  content: string;
  isGenerating: boolean;
  language: Language;
  logs: ActivityLog[];
  sources?: { uri: string; title: string }[];
  onSave?: () => void;
  isSaved?: boolean;
  apiKey: string;
}

export const ResultDisplay: React.FC<ResultDisplayProps> = ({ content, isGenerating, language, logs, sources, onSave, isSaved, apiKey }) => {
  const [showChatSession, setShowChatSession] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const langKey = language === Language.English ? 'en' : 'zh';
  const t = UI_TEXT;

  useEffect(() => {
    if (isGenerating && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isGenerating]);

  const handleDownloadWord = () => {
    if (!contentRef.current) return;
    const html = `<html><head><meta charset='utf-8'><style>body{font-family:'Times New Roman',serif;padding:40px;line-height:1.6;}h1{text-align:center;color:#4A5D23;}h2{border-bottom:2px solid #4A5D23;color:#4A5D23;margin-top:40px;}h3{color:#4A5D23;margin-top:30px;}.bib-entry{padding-left:2em;text-indent:-2em;margin-bottom:1em;}p{margin-bottom:1.5em;text-align:justify;}</style></head><body>${contentRef.current.innerHTML}</body></html>`;
    const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `SacredStudy_Manuscript_${new Date().getTime()}.doc`;
    link.click();
  };

  if (isGenerating) {
    return (
      <div className="bg-[#121212] rounded-2xl border border-white/10 shadow-3xl overflow-hidden font-mono text-[13px] max-w-4xl mx-auto my-12 animate-fade-in ring-1 ring-white/5">
        <div className="bg-white/5 p-5 border-b border-white/10 flex justify-between items-center">
          <div className="flex space-x-2">
            <div className="w-3 h-3 rounded-full bg-red-500/40"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500/40"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/40"></div>
          </div>
          <div className="text-white/40 text-[9px] uppercase tracking-[0.4em] font-bold">
            Scholar Grounding Synthesis
          </div>
        </div>
        <div className="p-10 h-[500px] overflow-y-auto space-y-5 scrollbar-thin scrollbar-thumb-white/10">
          {logs.map((log) => (
            <div key={log.id} className="flex gap-5 animate-log-entry border-l-2 border-white/5 pl-5 ml-2">
              <span className="text-white/20 shrink-0 tabular-nums">
                {log.timestamp.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit' })}
              </span>
              <div className="flex-1">
                <div className="flex items-center gap-4">
                  <span className={`
                    text-[9px] font-black px-2 py-0.5 rounded tracking-tighter
                    ${log.status === 'success' ? 'bg-green-500/20 text-green-400' : ''}
                    ${log.status === 'processing' ? 'bg-blue-500/20 text-blue-400' : ''}
                    ${log.status === 'error' ? 'bg-red-500/20 text-red-400' : ''}
                  `}>
                    {log.status.toUpperCase()}
                  </span>
                  <span className="text-white/90 font-medium">
                    {log.label[langKey]}
                  </span>
                </div>
                {log.detail && <p className="text-white/40 mt-2 text-xs font-light leading-relaxed">→ {log.detail}</p>}
              </div>
            </div>
          ))}
          <div ref={logsEndRef} className="flex items-center gap-3 text-sage-500 pt-4 ml-2">
            <span className="w-1.5 h-4 bg-sage-500 animate-pulse"></span>
            <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Structuring Professional Protocol...</span>
          </div>
        </div>
      </div>
    );
  }

  if (!content) return null;

  const isBibliographySection = (text: string) => {
    const lower = text.toLowerCase();
    return lower.includes("bibliography") || lower.includes("參考書目");
  };

  return (
    <>
      <div className="bg-paper shadow-3xl rounded-2xl overflow-hidden border border-stone-200 animate-fade-in max-w-5xl mx-auto ring-1 ring-black/5">
        <div className="bg-white/90 backdrop-blur-xl px-8 py-5 border-b border-stone-100 flex justify-between items-center no-print sticky top-20 z-30">
          <div className="flex items-center gap-4">
             <div className="flex gap-1.5">
               <div className="w-2 h-2 rounded-full bg-sage-500"></div>
               <div className="w-2 h-2 rounded-full bg-sage-200"></div>
             </div>
             <span className="text-[10px] uppercase tracking-[0.3em] font-black text-stone-400 border-l border-stone-200 pl-4">Biblical Manuscript Research</span>
          </div>
          <div className="flex gap-3">
            {onSave && (
              <button 
                onClick={onSave} 
                disabled={isSaved}
                className={`px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2.5 transition-all shadow-lg active:scale-95 ${
                  isSaved 
                    ? 'bg-green-500 text-white shadow-green-600/20' 
                    : 'bg-accent text-white shadow-accent/20 hover:bg-gold-600'
                }`}
              >
                 <span className="material-symbols-outlined text-lg">{isSaved ? 'check_circle' : 'library_add'}</span>
                 {isSaved ? t.saved[langKey] : t.saveToLibrary[langKey]}
              </button>
            )}
            <button onClick={() => setShowChatSession(true)} className="bg-sage-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2.5 hover:bg-sage-700 transition-all shadow-lg shadow-sage-600/20 active:scale-95">
               <span className="material-symbols-outlined text-lg">chat_bubble</span>
               {language === Language.English ? "Consult Assistant" : "諮詢助理"}
            </button>
            <button onClick={handleDownloadWord} className="bg-white border border-stone-200 px-5 py-2.5 rounded-xl text-sm font-bold text-stone-600 hover:bg-stone-50 transition-all active:scale-95">
               <span className="material-symbols-outlined text-lg">description</span>
               {language === Language.English ? "Export Word" : "匯出文件"}
            </button>
          </div>
        </div>

        <div className="p-16 md:p-24 lg:p-32">
          <div ref={contentRef} className="prose prose-stone prose-lg md:prose-2xl max-w-none font-serif leading-relaxed print-only-content">
            <Markdown
              components={{
                h1: (p) => <h1 className="text-6xl font-black text-sage-800 border-b-4 border-sage-600/10 pb-12 mb-20 tracking-tighter text-center italic" {...p} />,
                h2: (p) => {
                  const isBib = isBibliographySection(String(p.children || ""));
                  return (
                    <h2 
                      className={`text-4xl font-bold text-sage-700 mt-24 mb-12 pb-4 border-b-2 tracking-tight ${isBib ? 'border-gold-500' : 'border-sage-200/50'}`} 
                      {...p} 
                    />
                  );
                },
                h3: (p) => <h3 className="text-2xl font-bold text-sage-600 mt-14 mb-6 tracking-tight border-l-4 border-sage-100 pl-6" {...p} />,
                h4: (p) => <h4 className="text-xl font-bold text-sage-500 mt-10 mb-4 italic" {...p} />,
                blockquote: (p) => (
                  <blockquote className="border-l-8 border-gold-500 bg-stone-50/70 py-10 px-14 italic text-stone-800 rounded-r-3xl my-16 shadow-inner font-serif text-3xl leading-relaxed" {...p} />
                ),
                p: (p) => {
                  const text = String(p.children || "");
                  const parts = content.split(/#+ (?:Selected Bibliography|參考書目)/i);
                  const inBib = parts.length > 1 && content.indexOf(text) > content.toLowerCase().indexOf("bibliography");

                  if (inBib && text.length > 30) {
                     return <p className="mb-4 text-xl text-charcoal pl-8 -indent-8 leading-normal font-sans tracking-tight" {...p} />;
                  }

                  // Dropcap only for the very first paragraph of the document
                  const isFirstPara = content.indexOf(text) < 500;
                  return (
                    <p 
                      className={`mb-12 text-charcoal text-justify leading-[1.8] opacity-95 ${isFirstPara ? 'first-letter:text-6xl first-letter:font-bold first-letter:mr-3 first-letter:float-left first-letter:mt-1 first-letter:text-sage-700' : ''}`} 
                      {...p} 
                    />
                  );
                },
                ul: (p) => <ul className="list-disc pl-10 space-y-4 mb-12 marker:text-gold-500" {...p} />,
                ol: (p) => <ol className="list-decimal pl-10 space-y-4 mb-12 marker:text-sage-600 marker:font-bold" {...p} />,
                li: (p) => <li className="text-xl leading-relaxed text-charcoal" {...p} />,
                strong: (p) => <strong className="font-bold text-sage-900 border-b border-gold-500/10" {...p} />,
                em: (p) => <em className="italic text-sage-800" {...p} />
              }}
            >
              {content}
            </Markdown>

            {/* Grounding Sources (Verified Hyperlinks) */}
            {sources && sources.length > 0 && (
              <div className="mt-32 pt-16 border-t-4 border-stone-100 no-print">
                <div className="flex items-center gap-6 mb-12">
                   <h4 className="text-[12px] font-black text-sage-600 uppercase tracking-[0.4em] whitespace-nowrap">
                    Digital Access Grounding
                  </h4>
                  <div className="h-px bg-stone-200 w-full"></div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {sources.map((source, i) => (
                    <a 
                      key={i} 
                      href={source.uri} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="group p-6 bg-white border border-stone-200 rounded-2xl hover:border-sage-400 hover:shadow-xl transition-all flex flex-col justify-between"
                    >
                      <div>
                        <div className="text-[10px] text-gold-600 font-black uppercase tracking-widest mb-2">Primary Access</div>
                        <div className="text-lg font-bold text-sage-800 group-hover:text-sage-600 leading-tight mb-2 line-clamp-2">{source.title}</div>
                      </div>
                      <div className="text-[11px] text-stone-400 font-mono truncate">{source.uri}</div>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      <ChatSession 
        contextContent={content} 
        language={language} 
        isVisible={showChatSession}
        onClose={() => setShowChatSession(false)} 
        apiKey={apiKey}
      />
    </>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from '@google/genai';
import Markdown from 'react-markdown';
import { Language } from '../types';

interface ChatSessionProps {
  contextContent: string;
  language: Language;
  onClose: () => void;
  isVisible: boolean;
  apiKey: string;
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const ChatSession: React.FC<ChatSessionProps> = ({ contextContent, language, onClose, isVisible, apiKey }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const isChinese = language === Language.TraditionalChinese;

  useEffect(() => {
    // Initialize chat session whenever the context content changes (new report generated).
    const initChat = async () => {
      if (!apiKey) return;

      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `
        You are a PhD-level Theological Research Assistant.
        Report Context: """${contextContent.substring(0, 10000)}"""

        FORMATTING RULES:
        1. NEVER wrap Greek, Hebrew, or non-English text in dollar signs ($). 
        2. Use standard Unicode characters for all scripts.
        3. Use Markdown italics for transliterations and bold for original scripts.

        Tasks:
        1. Answer follow-ups based on the generated report.
        2. Expand using your internal scholarly database for deep theology.
        3. Maintain a tone of professional excellence.
        Language: ${isChinese ? 'Traditional Chinese' : 'English'}
      `;

      try {
        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction,
            temperature: 0.7,
          }
        });
        chatRef.current = chat;
        const greeting = isChinese 
          ? "報告已生成。我是您的神學研究助理，針對上述內容或其原始語境，您有什麼需要更深入探討的嗎？"
          : "The analysis is complete. I am your theological research assistant. How can I further assist your inquiry into this text or its historical implications?";
        setMessages([{ role: 'model', text: greeting }]);
      } catch (error) {
        console.error("Chat init error:", error);
      }
    };
    initChat();
  }, [contextContent, isChinese, apiKey]);

  useEffect(() => {
    if (isVisible) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isVisible]);

  const handleSend = async () => {
    if (!input.trim() || !chatRef.current || isLoading) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const result = await chatRef.current.sendMessageStream({ message: userMsg });
      setMessages(prev => [...prev, { role: 'model', text: '' }]);
      let fullText = '';
      for await (const chunk of result) {
        fullText += (chunk as GenerateContentResponse).text || '';
        setMessages(prev => {
          const newMsgs = [...prev];
          newMsgs[newMsgs.length - 1] = { role: 'model', text: fullText };
          return newMsgs;
        });
      }
    } catch (error: any) {
      const errorMsg = error?.message || "";
      if (errorMsg.includes("429")) {
        setMessages(prev => [...prev, { role: 'model', text: "Quota Exhausted: Your current protocol has reached its rate limit. Please wait a moment." }]);
      } else {
        setMessages(prev => [...prev, { role: 'model', text: "Service Error: Connection interrupted. Please try re-activating your protocol." }]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md animate-fade-in p-4"
      style={{ display: isVisible ? 'flex' : 'none' }}
    >
      <div className="bg-white w-full max-w-3xl h-[85vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col border border-white/20">
        <div className="bg-sage-600 p-5 flex justify-between items-center shadow-lg z-10 shrink-0">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center border border-white/30">
              <span className="text-xl">📜</span>
            </div>
            <div>
              <h3 className="text-xl font-serif font-bold text-white tracking-wide">Research Consultation</h3>
              <p className="text-sage-100 text-xs uppercase tracking-widest font-medium">Session: Scholarly AI Assistant</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full text-white transition-all">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 bg-ivory space-y-6">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] rounded-2xl px-6 py-4 shadow-sm font-serif ${msg.role === 'user' ? 'bg-sage-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-charcoal rounded-tl-none'}`}>
                <div className="prose prose-sm max-w-none leading-relaxed">
                  <Markdown>{msg.text}</Markdown>
                </div>
              </div>
            </div>
          ))}
          {isLoading && <div className="text-sage-400 italic text-sm animate-pulse px-2">Assistant is synthesizing response...</div>}
          <div ref={messagesEndRef} />
        </div>
        <div className="p-6 bg-white border-t border-stone-200">
          <div className="relative flex items-end gap-3">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={isChinese ? "輸入問題... (Command+Enter 發送)" : "Inquire further... (Command+Enter to send)"}
              className="w-full p-4 pr-14 max-h-40 min-h-[60px] bg-stone-50 border border-stone-300 rounded-xl focus:ring-2 focus:ring-sage-500 outline-none resize-none transition-all font-serif"
              rows={1}
            />
            <button 
              onClick={handleSend} 
              disabled={!input.trim() || isLoading} 
              className="absolute right-3 bottom-3 p-3 bg-sage-600 text-white rounded-xl hover:bg-sage-700 disabled:bg-stone-300 transition-all"
              title={isChinese ? "發送 (Cmd+Enter)" : "Send (Cmd+Enter)"}
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { StudyConfig, Language, StudyType, KnowledgeLevel, ActivityLog } from "../types";
import { APPROACHES, TRADITIONS } from "../constants";

const MODEL_NAME = "gemini-3-pro-preview";

const getGenreProtocol = (type: StudyType, isChinese: boolean) => {
  switch (type) {
    case StudyType.Academic:
      return {
        role: "Senior Biblical Scholar and Journal Editor",
        style: "Formal Peer-Reviewed Journal Article",
        structure: [
          "Abstract & Introduction", 
          "Linguistic & Structural Analysis (Original Languages)", 
          "Methodological Analysis (Selected Approaches)", 
          "Tradition History (Selected Traditions)", 
          "Thematic Synthesis", 
          "Conclusion", 
          "Selected Bibliography"
        ],
        constraints: "MANDATORY: Produce a lengthy, rigorous academic paper. NO bullet points in main text. Use sophisticated paragraphs. Include Greek/Hebrew analysis with transliteration. Rigorously apply the selected critical methods. CITATIONS: Use Chicago Author-Date style (e.g., Brown 2020, 45) in-text."
      };
    case StudyType.Sermon:
      return {
        role: "Master Homiletician",
        style: "Expository Sermon Manuscript",
        structure: [
          "The Hook (Introduction)", 
          "The Book (Linguistic & Structural Exegesis)", 
          "The Look (Theological Illustration)", 
          "The Took (Application & Practice)", 
          "The Charge (Conclusion)",
          "Selected Bibliography"
        ],
        constraints: "MANDATORY: Write as a full spoken manuscript. Use rhythmic, persuasive prose. Include deep insights from original languages (explained simply). Connect text structure to sermon structure. Cite scholars naturally (e.g., 'As N.T. Wright notes...')."
      };
    case StudyType.Devotional:
      return {
        role: "Spiritual Director and Theologian",
        style: "Deeply Theological Devotional Essay",
        structure: [
          "Invocation & Context", 
          "Linguistic Meditation (Keywords)", 
          "Theological Reflection", 
          "Heart-Application", 
          "Closing Prayer",
          "Selected Bibliography"
        ],
        constraints: "MANDATORY: Continuous, flowing prose. Deep dive into 1-2 key Hebrew/Greek words. Focus on internal transformation. Weave scholarship in gently."
      };
    case StudyType.Discussion:
      return {
        role: "Socratic Pedagogue",
        style: "Comprehensive Discussion Guide",
        structure: [
          "Session Objective & Context", 
          "Structural & Linguistic Notes", 
          "Observation Queries", 
          "Interpretation Challenges", 
          "Application Dialogue",
          "Selected Bibliography"
        ],
        constraints: "Detailed background notes required. Questions should be open-ended and profound."
      };
    default: // Comprehensive
      return {
        role: "Systematic Theological Consultant",
        style: "Comprehensive Encyclopedic Analysis",
        structure: [
          "Executive Summary & Context", 
          "Linguistic & Structural Analysis", 
